mapper.select:
SELECT p.* FROM post p
WHERE p.deleted = 0
AND p.review_status IN (0, 1)

    AND p.type = #{type}


    AND p.item_category = #{itemCategory}


    AND p.status = #{status}


    AND (p.title LIKE CONCAT('%', #{keyword}, '%')
         OR p.description LIKE CONCAT('%', #{keyword}, '%'))

ORDER BY p.create_time DESC
